makeOperationId(operation, path) {
	// make a nice camelCase operationID
	// e.g. get /user/{name}  becomes getUserByName
	const firstUpper = (str) =>
		str.substring(0, 1).toUpperCase() + str.substring(1);
	const by = (_matched, p1) => `By${firstUpper(p1)}`;
	const parts = path.split("/").slice(1);
	parts.unshift(operation);
	const opId = parts
		.map((item, i) => (i > 0 ? firstUpper(item) : item))
		.join("")
		.replace(/{(\w+)}/g, by)
		.replace(/[^a-z]/gi, "");
	return opId;
}

export async function* walk(
  dir: string,
  ignorePatterns: RegExp[] = [],
): AsyncIterable<{ stats: Stats; path: string }> {
  const sliceAt = dir.length + (dir.endsWith('/') ? 0 : 1)
  for await (const match of klaw(dir)) {
    const pathEntry = match.path.slice(sliceAt)
    if (ignorePatterns.some((ignorePattern) => ignorePattern.test(match.path))) {
      continue
    }
    if (pathEntry === '') {
      continue
    }
    yield { stats: match.stats, path: pathEntry }
  }
}

partialSchemaProperties = (schemaId: string, schema: Record<string, JSONSchema7Extended>) =>
  Object.keys(schema)
    .filter(key => !schema[key]._options?.hidden && !schema[key].readOnly)
    .reduce((props, key) => ({
      ...props,
      [key]: { $ref: `${schemaId}#/definitions/entity/properties/${key}` }
    }), {})

asDateTime (date) {
  if (date === null) return '""'
  if (date instanceof Date) {
    return '"' + date.toISOString() + '"'
  }
  if (typeof date === 'string') {
    return '"' + date + '"'
  }
  throw new Error(`The value "${date}" cannot be converted to a date-time.`)
}

asTime (date) {
  if (date === null) return '""'
  if (date instanceof Date) {
    return '"' + new Date(date.getTime() - (date.getTimezoneOffset() * 60000)).toISOString().slice(11, 19) + '"'
  }
  if (typeof date === 'string') {
    return '"' + date + '"'
  }
  throw new Error(`The value "${date}" cannot be converted to a time.`)
}

asDate (date) {
  if (date === null) return '""'
  if (date instanceof Date) {
    return '"' + new Date(date.getTime() - (date.getTimezoneOffset() * 60000)).toISOString().slice(0, 10) + '"'
  }
  if (typeof date === 'string') {
    return '"' + date + '"'
  }
  throw new Error(`The value "${date}" cannot be converted to a date.`)
}
